import{_ as o,o as e,c as n,ag as i}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"채널 위치 파싱","description":"인바운드 채널 위치 파싱 (Telegram/WhatsApp/Matrix) 및 컨텍스트 필드","frontmatter":{"title":"채널 위치 파싱","description":"인바운드 채널 위치 파싱 (Telegram/WhatsApp/Matrix) 및 컨텍스트 필드"},"headers":[],"relativePath":"channels/location.md","filePath":"channels/location.md","lastUpdated":null}'),l={name:"channels/location.md"};function s(t,a,c,d,p,r){return e(),n("div",null,[...a[0]||(a[0]=[i(`<p>OpenClaw는 채팅 채널에서 공유된 위치를 다음과 같이 정규화합니다:</p><ul><li>인바운드 본문에 추가되는 간결한 좌표 텍스트, 그리고</li><li>자동 응답 컨텍스트 페이로드의 구조화된 필드. 채널이 제공하는 레이블, 주소, 캡션/코멘트는 사용자 본문에 인라인으로가 아니라 공유 신뢰할 수 없는 메타데이터 JSON 블록을 통해 프롬프트에 렌더링됩니다.</li></ul><p>현재 지원되는 항목:</p><ul><li><strong>Telegram</strong> (위치 핀 + 장소 + 라이브 위치)</li><li><strong>WhatsApp</strong> (locationMessage + liveLocationMessage)</li><li><strong>Matrix</strong> (<code>geo_uri</code>가 있는 <code>m.location</code>)</li></ul><h2 id="텍스트-포맷" tabindex="-1">텍스트 포맷 <a class="header-anchor" href="#텍스트-포맷" aria-label="Permalink to &quot;텍스트 포맷&quot;">​</a></h2><p>위치는 대괄호 없이 친숙한 라인으로 렌더링됩니다:</p><ul><li>핀: <ul><li><code>📍 48.858844, 2.294351 ±12m</code></li></ul></li><li>명명된 장소: <ul><li><code>📍 48.858844, 2.294351 ±12m</code></li></ul></li><li>라이브 공유: <ul><li><code>🛰 Live location: 48.858844, 2.294351 ±12m</code></li></ul></li></ul><p>채널에 레이블, 주소 또는 캡션/코멘트가 포함된 경우 컨텍스트 페이로드에 보존되며 프롬프트에 펜스된 신뢰할 수 없는 JSON으로 표시됩니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Location (untrusted metadata):</span></span>
<span class="line"><span>\`\`\`json</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;latitude&quot;: 48.858844,</span></span>
<span class="line"><span>  &quot;longitude&quot;: 2.294351,</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;Eiffel Tower&quot;,</span></span>
<span class="line"><span>  &quot;address&quot;: &quot;Champ de Mars, Paris&quot;,</span></span>
<span class="line"><span>  &quot;caption&quot;: &quot;Meet here&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><h2 id="컨텍스트-필드" tabindex="-1">컨텍스트 필드 <a class="header-anchor" href="#컨텍스트-필드" aria-label="Permalink to &quot;컨텍스트 필드&quot;">​</a></h2><p>위치가 있는 경우 다음 필드가 <code>ctx</code>에 추가됩니다:</p><ul><li><code>LocationLat</code> (숫자)</li><li><code>LocationLon</code> (숫자)</li><li><code>LocationAccuracy</code> (숫자, 미터; 선택)</li><li><code>LocationName</code> (문자열; 선택)</li><li><code>LocationAddress</code> (문자열; 선택)</li><li><code>LocationSource</code> (<code>pin | place | live</code>)</li><li><code>LocationIsLive</code> (불리언)</li><li><code>LocationCaption</code> (문자열; 선택)</li></ul><p>프롬프트 렌더러는 <code>LocationName</code>, <code>LocationAddress</code>, <code>LocationCaption</code>을 신뢰할 수 없는 메타데이터로 취급하고 다른 채널 컨텍스트와 동일한 제한된 JSON 경로를 통해 직렬화합니다.</p><h2 id="채널-참고-사항" tabindex="-1">채널 참고 사항 <a class="header-anchor" href="#채널-참고-사항" aria-label="Permalink to &quot;채널 참고 사항&quot;">​</a></h2><ul><li><strong>Telegram</strong>: 장소는 <code>LocationName/LocationAddress</code>로 매핑됩니다. 라이브 위치는 <code>live_period</code>를 사용합니다.</li><li><strong>WhatsApp</strong>: <code>locationMessage.comment</code>와 <code>liveLocationMessage.caption</code>이 <code>LocationCaption</code>을 채웁니다.</li><li><strong>Matrix</strong>: <code>geo_uri</code>는 핀 위치로 파싱됩니다. 고도는 무시되고 <code>LocationIsLive</code>는 항상 false입니다.</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/nodes/location-command">위치 명령 (노드)</a></li><li><a href="/openclaw-docs-ko/nodes/camera">카메라 캡처</a></li><li><a href="/openclaw-docs-ko/nodes/media-understanding">미디어 이해</a></li></ul>`,17)])])}const m=o(l,[["render",s]]);export{h as __pageData,m as default};
